import { z } from "zod";
import type { ZodSchema } from "zod/v3";

export abstract class BaseValidator {
  protected validateBody<T extends ZodSchema>(schema: T) {
    return schema;
  }

  protected validateQuery<T extends ZodSchema>(schema: T) {
    return schema;
  }

  protected validateParams<T extends ZodSchema>(schema: T) {
    return schema;
  }

  protected paginationQuery() {
    return z.object({
      page: z.coerce.number().min(1).default(1),
      limit: z.coerce.number().min(1).max(100).default(10),
    });
  }
}
