import { AnthropicProvider } from "./ai";
import {
  ConversationsController,
  ConversationsRoutes,
  ConversationsService,
} from "./modules/conversations";

// AI layer — the single LLM provider instance, injected into feature services
// that need to call the model. Reads ANTHROPIC_API_KEY from env by default.
export const llmProvider = new AnthropicProvider();

export const conversationsService = new ConversationsService();

export const conversationsController = new ConversationsController(
  conversationsService
);

export const conversationsRoutes = new ConversationsRoutes(
  conversationsController
);
